#include <stdio.h>
#include <stdlib.h>

#define N 10

// Structure for adjacency list node
struct Node {
    int vertex;
    struct Node* next;
};

// Array of adjacency lists
struct Node* adj[N];

// Array to keep track of visited nodes
int vis[N];

// Function to create a new adjacency list node
struct Node* createNode(int v) {
    struct Node* newNode = (struct Node*)malloc(sizeof(struct Node));
    newNode->vertex = v;
    newNode->next = NULL;
    return newNode;
}

// Function to add an edge to an undirected graph
void addEdge(int src, int dest) {
    struct Node* newNode = createNode(dest);
    newNode->next = adj[src];
    adj[src] = newNode;

    newNode = createNode(src);
    newNode->next = adj[dest];
    adj[dest] = newNode;
}

// Breadth First Search function using array-based queue
void bfs(int v) {
    int queue[N];
    int front = 0, rear = 0;

    queue[rear++] = v;

    while (front < rear) {
        int u = queue[front++];

        if (vis[u]) {
            continue;
        }

        vis[u] = 1;
        printf("Currently Traversing Vertex in BFS: %d\n", u);

        struct Node* temp = adj[u];
        // Using a temporary array to store the neighbors for correct order processing
        int neighbors[N], count = 0;
        while (temp) {
            neighbors[count++] = temp->vertex;
            temp = temp->next;
        }
        for (int i = count - 1; i >= 0; i--) {
            if (!vis[neighbors[i]]) {
                queue[rear++] = neighbors[i];
            }
        }
    }
}

// Depth First Search function
void dfs(int v) {
    if (vis[v]) {
        return;
    }
    printf("Currently Traversing Vertex in DFS: %d\n", v);
    vis[v] = 1;

    struct Node* temp = adj[v];
    // Using a temporary array to store the neighbors for correct order processing
    int neighbors[N], count = 0;
    while (temp) {
        neighbors[count++] = temp->vertex;
        temp = temp->next;
    }
    for (int i = count - 1; i >= 0; i--) {
        dfs(neighbors[i]);
    }
}

int main() {
    // Building adjacency list for Undirected Graph
    addEdge(1, 2);
    addEdge(1, 3);
    addEdge(1, 4);
    addEdge(2, 4);
    addEdge(2, 6);
    addEdge(3, 5);
    addEdge(4, 2);
    addEdge(5, 6);

    bfs(1); // Start bfs from node 1

    // Reset visited array
    for (int i = 0; i < N; i++) vis[i] = 0;

    printf("\n");
    dfs(1); // Start dfs from node 1
    return 0;
}

