import java.util.*;

class main {
    static int N = 10;
    static List<Integer>[] adj = new ArrayList[N];
    static boolean[] vis = new boolean[N];

    // Breadth-First Search
    public static void bfs(int v) {
        Queue<Integer> queue = new LinkedList<>();
        queue.add(v); // Push the source vertex into the queue

        while (!queue.isEmpty()) { // Run until the queue is empty
            int u = queue.poll();

            if (vis[u]) { // If the vertex is already processed, continue
                continue;
            }

            vis[u] = true; // Set the node as visited

            System.out.println("Currently Traversing Vertex in BFS: " + u);

            for (int x : adj[u]) {
                // Push the vertex into the queue to be processed
                queue.add(x);
            }
        }
    }

    // Depth-First Search
    public static void dfs(int v) {
        if (vis[v]) {
            return;
        }
        System.out.println("Currently Traversing Vertex in DFS: " + v);
        vis[v] = true;
        for (int u : adj[v]) {
            dfs(u);
        }
    }

    public static void main(String[] args) {
        // Initialize adjacency list for Undirected Graph
        for (int i = 0; i < N; i++) {
            adj[i] = new ArrayList<>();
        }

        adj[1].add(2);
        adj[1].add(3);
        adj[1].add(4);

        adj[2].add(1);
        adj[2].add(4);
        adj[2].add(6);

        adj[3].add(1);
        adj[3].add(5);

        adj[4].add(1);
        adj[4].add(2);

        adj[5].add(3);
        adj[5].add(6);

        adj[6].add(2);
        adj[6].add(5);

        bfs(1); // Start BFS from node 1

        for (int i = 1; i < N; i++) {
            vis[i] = false; // Reset visited array
        }

        System.out.println();
        dfs(1); // Start DFS from node 1
    }
}
